Combine cc.Label with actions for animated score updates:

```typescript
class ScoreDisplay extends cc.Node {
    private label: cc.Label;
    private currentScore: number = 0;

    init(): boolean {
        this.label = cc.Label.createWithSystemFont('0', 'Impact', 36);
        this.label.setTextColor(cc.color(255, 220, 0));
        this.label.enableOutline(cc.color(0, 0, 0, 255), 2);
        this.label.setPosition(0, 0);
        this.addChild(this.label);
        return true;
    }

    setScore(value: number): void {
        this.currentScore = value;
        this.label.setString(String(value));
        this.label.stopAllActions();
        this.label.runAction(cc.sequence(
            cc.scaleTo(0.1, 1.3).easing(cc.easeOut(2)),
            cc.scaleTo(0.15, 1.0).easing(cc.easeSineOut())
        ));
    }

    addScore(delta: number): void {
        this.setScore(this.currentScore + delta);
    }
}
```

