Schedule updates and change color based on time:

```typescript
const timerLabel = cc.Label.createWithSystemFont('3:00', 'Impact', 40);
timerLabel.setTextColor(cc.color(255, 255, 255));
timerLabel.enableOutline(cc.color(0, 0, 0, 255), 2);
timerLabel.setPosition(240, 290);
this.addChild(timerLabel);

let timeLeft = 180;

function formatTime(s: number): string {
    const min = Math.floor(s / 60);
    const sec = s % 60;
    return min + ':' + (sec < 10 ? '0' : '') + sec;
}

this.schedule((dt: number) => {
    timeLeft--;
    timerLabel.setString(formatTime(timeLeft));

    if (timeLeft <= 10) {
        timerLabel.setTextColor(cc.color(255, 50, 50));
        // Pulse effect
        timerLabel.stopAllActions();
        timerLabel.runAction(cc.sequence(
            cc.scaleTo(0.1, 1.2),
            cc.scaleTo(0.2, 1.0)
        ));
    }

    if (timeLeft <= 0) {
        this.unschedule(arguments.callee);
        this.onTimeUp();
    }
}, 1.0);
```

Use `getLetter()` to access each character as a sprite (BMFont/TTF only):

```typescript
const label = cc.Label.createWithBMFont('res/fonts/game.fnt', 'GAME OVER');
label.setPosition(240, 160);
this.addChild(label);

// Wave animation
const length = label.getStringLength();
for (let i = 0; i < length; i++) {
    const letter = label.getLetter(i);
    if (letter) {
        letter.runAction(cc.repeatForever(cc.sequence(
            cc.delayTime(i * 0.1),
            cc.moveBy(0.3, cc.p(0, 10)).easing(cc.easeSineInOut()),
            cc.moveBy(0.3, cc.p(0, -10)).easing(cc.easeSineInOut())
        )));
    }
}

// Pop-in reveal
for (let i = 0; i < length; i++) {
    const letter = label.getLetter(i);
    if (letter) {
        letter.setScale(0);
        letter.setOpacity(0);
        letter.runAction(cc.sequence(
            cc.delayTime(i * 0.08),
            cc.spawn(
                cc.scaleTo(0.2, 1.0).easing(cc.easeBackOut()),
                cc.fadeIn(0.15)
            )
        ));
    }
}
```

