Build the string incrementally:

```typescript
function typewriter(
    label: cc.Label, fullText: string, charDelay: number,
    parent: cc.Node, onComplete?: () => void
): void {
    let idx = 0;
    label.setString('');

    parent.schedule((dt: number) => {
        idx++;
        label.setString(fullText.substring(0, idx));
        if (idx >= fullText.length) {
            parent.unschedule(arguments.callee);
            if (onComplete) onComplete();
        }
    }, charDelay, fullText.length - 1, 0);
}

