function createTooltip(text: string, pos: cc.Point): ccui.Layout {
    const label = cc.Label.createWithSystemFont(text, 'Arial', 14);
    label.setTextColor(cc.color(255, 255, 220));
    label.setDimensions(180, 0);
    label.updateContent();

    const padding = 10;
    const labelSize = label.getContentSize();
    const bgWidth = labelSize.width + padding * 2;
    const bgHeight = labelSize.height + padding * 2;

    const tooltip = new ccui.Layout();
    tooltip.setSize(cc.size(bgWidth, bgHeight));
    tooltip.setBackGroundColorType(ccui.Layout.BG_COLOR_SOLID);
    tooltip.setBackGroundColor(cc.color(20, 20, 40));
    tooltip.setBackGroundColorOpacity(230);
    tooltip.setPosition(pos.x, pos.y);

    label.setPosition(bgWidth / 2, bgHeight / 2);
    tooltip.addChild(label);

    // Fade in
    tooltip.setOpacity(0);
    tooltip.runAction(cc.fadeIn(0.2));

    return tooltip;
}

