CharMap is fastest for numeric-only displays:

```typescript
class FPSCounter extends cc.Node {
    private label: cc.Label;
    private frames: number = 0;
    private elapsed: number = 0;

    onEnter(): void {
        super.onEnter();
        // CharMap with digits 0-9 (ASCII 48-57)
        this.label = cc.Label.createWithCharMap('res/fonts/fps_digits.png', 12, 18, 48);
        this.label.setString('60');
        this.label.setAnchorPoint(cc.p(1, 1));
        this.addChild(this.label);

        this.scheduleUpdate();
    }

    update(dt: number): void {
        this.frames++;
        this.elapsed += dt;
        if (this.elapsed >= 0.5) {
            const fps = Math.round(this.frames / this.elapsed);
            this.label.setString(String(fps));
            this.frames = 0;
            this.elapsed = 0;
        }
    }

    onExit(): void {
        this.unscheduleUpdate();
        super.onExit();
    }
}
```

